from dataclasses import dataclass, field
from datetime import datetime, timedelta
from enum import Enum

class WindowPhase(str, Enum):
    PRE_WINDOW  = "pre_window"
    DEPLOY      = "deploy"
    MONITOR     = "monitor"
    CLOSED      = "closed"
    ROLLED_BACK = "rolled_back"

@dataclass
class UpgradeWindow:
    dependency_name: str
    from_version: str
    to_version: str
    scheduled_start: datetime
    on_call_engineer: str

    # durations (minutes)
    deploy_duration_minutes: int = 30
    monitor_duration_minutes: int = 60

    phase: WindowPhase = WindowPhase.PRE_WINDOW
    phase_log: list[tuple[str, datetime]] = field(default_factory=list)

    @property
    def window_end(self) -> datetime:
        return self.scheduled_start + timedelta(
            minutes=self.deploy_duration_minutes + self.monitor_duration_minutes
        )

    def transition(self, new_phase: WindowPhase, at: datetime) -> None:
        self.phase = new_phase
        self.phase_log.append((new_phase.value, at))

    def is_overdue(self, now: datetime) -> bool:
        return now > self.window_end and self.phase not in (
            WindowPhase.CLOSED, WindowPhase.ROLLED_BACK
        )

    def duration_so_far(self, now: datetime) -> timedelta:
        return now - self.scheduled_start

from dataclasses import dataclass
from datetime import date, timedelta
from enum import Enum

class WindowSlot(str, Enum):
    # Scheduled recurring slots — Tuesday/Thursday 10am-12pm business time
    RECURRING_TUESDAY    = "tuesday_10am"
    RECURRING_THURSDAY   = "thursday_10am"
    # Emergency slot — any weekday, requires IC approval
    EMERGENCY            = "emergency"

@dataclass
class UpgradeSchedule:
    dependency_name: str
    upgrade_track: str    # from risk scoring: maintain, prioritise, plan, escalate

    def recommended_slot(self) -> WindowSlot:
        if self.upgrade_track in ("escalate", "prioritise"):
            return WindowSlot.EMERGENCY
        return WindowSlot.RECURRING_TUESDAY   # default to next Tuesday slot

    def latest_acceptable_window_date(self, from_date: date) -> date:
        deadlines = {
            "escalate":   from_date + timedelta(days=1),
            "prioritise": from_date + timedelta(days=7),
            "plan":       from_date + timedelta(days=90),
            "maintain":   from_date + timedelta(days=30),
        }
        return deadlines[self.upgrade_track]

    def next_recurring_slot(self, from_date: date) -> date:
        """Returns the next Tuesday on or after from_date."""
        days_until_tuesday = (1 - from_date.weekday()) % 7  # Monday=0, Tuesday=1
        if days_until_tuesday == 0 and from_date.weekday() == 1:
            return from_date
        return from_date + timedelta(days=days_until_tuesday or 7)

    def fits_in_recurring_slot(self, from_date: date) -> bool:
        next_slot = self.next_recurring_slot(from_date)
        return next_slot <= self.latest_acceptable_window_date(from_date)

from dataclasses import dataclass, field
from datetime import datetime

@dataclass
class CustomerMaintenancePreferences:
    account_id: str
    account_name: str
    preferred_window_hours_utc: tuple[int, int]  # (start_hour, end_hour) UTC
    blackout_periods: list[tuple[datetime, datetime]] = field(default_factory=list)
    advance_notice_hours: float = 24.0

    def is_blackout(self, window_start: datetime) -> bool:
        for start, end in self.blackout_periods:
            if start <= window_start <= end:
                return True
        return False

    def is_preferred_hour(self, window_start: datetime) -> bool:
        start_h, end_h = self.preferred_window_hours_utc
        return start_h <= window_start.hour < end_h

    def compliance_issues(self, window_start: datetime, notice_sent_at: datetime) -> list[str]:
        issues = []
        if self.is_blackout(window_start):
            issues.append(f"window falls within blackout period for {self.account_name}")
        if not self.is_preferred_hour(window_start):
            start_h, end_h = self.preferred_window_hours_utc
            issues.append(
                f"window hour {window_start.hour}:00 UTC outside preferred "
                f"{start_h}:00-{end_h}:00 UTC for {self.account_name}"
            )
        notice_lead = (window_start - notice_sent_at).total_seconds() / 3600
        if notice_lead < self.advance_notice_hours:
            issues.append(
                f"notice sent {notice_lead:.1f}h before window; "
                f"{self.account_name} requires {self.advance_notice_hours}h"
            )
        return issues
